import{_ as t,o as r,c as o,a2 as l}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"F05: 應收帳款品質與收款天數 - 財務審計專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/2492_華新科/20260512/F05_應收帳款品質與收款天數.md","filePath":"審計報告庫/財務審計/2492_華新科/20260512/F05_應收帳款品質與收款天數.md"}'),i={name:"審計報告庫/財務審計/2492_華新科/20260512/F05_應收帳款品質與收款天數.md"};function e(n,a,s,h,g,d){return r(),o("div",null,[...a[0]||(a[0]=[l('<h1 id="f05-應收帳款品質與收款天數-財務審計專家-審計報告" tabindex="-1">F05: 應收帳款品質與收款天數 - 財務審計專家 審計報告 <a class="header-anchor" href="#f05-應收帳款品質與收款天數-財務審計專家-審計報告" aria-label="Permalink to &quot;F05: 應收帳款品質與收款天數 - 財務審計專家 審計報告&quot;">​</a></h1><blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p></blockquote><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>應收帳款規模與週轉天數(DSO)變動為何？是否存在客戶拖欠或虛增營收風險？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：DSO 101天偏長但帳齡健康(95%未逾期)，備抵僅0.78%，無單一客戶&gt;10%。應收品質穩健。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：截至2025年報</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>DSO趨勢</strong>：2023年98天→2024年102天→2025年101天，三年穩定在100±2天，無顯著惡化。</li><li><strong>AR/營收比</strong>：26.8%→28.0%→27.7%，佔比持穩，AR增速（2023→2025年+15%）略高於營收增速(+11.2%)，差距可控。</li><li><strong>備抵損失率</strong>：僅0.78%（84百萬/108億總帳面金額），提列充足。</li><li><strong>診斷見解</strong>：DSO偏長為客戶信用條件(60-150天)的結構性結果，非管理失當。95%以上AR未逾期為核心品質證明。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-dso趨勢與營收品質判斷" tabindex="-1">1. DSO趨勢與營收品質判斷 <a class="header-anchor" href="#_1-dso趨勢與營收品質判斷" aria-label="Permalink to &quot;1. DSO趨勢與營收品質判斷&quot;">​</a></h3><ul><li><strong>DSO穩定無背離</strong>：98天→102天→101天。2024年微升至102天後2025年回穩至101天，無持續惡化，AR與營收走勢基本同步。</li><li><strong>季度AR趨勢</strong>：2025年Q3 AR達年度高峰105.7億之後Q4降至100.5億，顯示Q4季底積極收款。Q1 2026再升至106.9億因營收成長(95.4億為同期最高)帶動AR自然增加。</li><li><strong>結論</strong>：無「放帳衝業績」跡象，AR變動合理反映營收規模。</li></ul><h3 id="_2-帳齡分析與呆帳風險" tabindex="-1">2. 帳齡分析與呆帳風險 <a class="header-anchor" href="#_2-帳齡分析與呆帳風險" aria-label="Permalink to &quot;2. 帳齡分析與呆帳風險&quot;">​</a></h3><ul><li><strong>逾期狀況極低</strong>：2025年底未逾期AR達82.4億+22.4億=104.8億（總帳面108億中佔97%），逾期1-30天僅0.3億、31-90天約2億、91天以上僅0.05億。逾180天僅3.5萬（幾乎全額提列）。</li><li><strong>備抵損失充足</strong>：2025年備抵損失8,409萬（vs 2024年9,273萬略降），佔總AR 0.78%，考量極低逾期比例，提列水準合理。</li><li><strong>客戶群A vs B區分</strong>：客戶群A(主要客戶)採用較嚴格的0-4%損失率；客戶群B(被投資公司或特定交易對象)採0%損失率(未逾期)至100%(180天以上)，分層管理嚴謹。</li></ul><h3 id="_3-客戶分散度與集中風險" tabindex="-1">3. 客戶分散度與集中風險 <a class="header-anchor" href="#_3-客戶分散度與集中風險" aria-label="Permalink to &quot;3. 客戶分散度與集中風險&quot;">​</a></h3><ul><li><strong>無單一客戶&gt;10%</strong>：年報明確揭露無單一客戶佔營收超10%。客戶包括EMS廠(鴻海/廣達/緯創等)、電源供應商(台達/光寶)、車用Tier 1，三大領域分散。</li><li><strong>產品別風險分散</strong>：MLCC(41.7%)+晶片電阻(22%)+RF(17.2%)+其他(19.1%)，應用面橫跨消費/車用/工業/通訊/AI，無單一終端市場過度集中。</li><li><strong>關係人應收極低</strong>：應收關係人款項極微小，反映公司與關係企業交易以正常商業條件進行，無異常資金貸與。</li></ul><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>DSO 100天的營運資金壓力</strong>：收款期超過3個月代表每賺100元營收需墊付約27元的資金成本（AR/營收比27.7%）。利率上升期間利息費用隨之增加（2025年利息費用5.5億，為2023年3.9億的1.4倍）。</li><li><strong>2025年Q3 AR異常升高警訊</strong>：Q3 AR達105.7億為近年高點，Q4雖回落但Q1 2026又升至106.9億。若後續營收動能減速但AR續增，將出現死亡交叉風險。</li><li><strong>產業客戶倒帳連鎖風險</strong>：雖目前分散，但若發生系統性風險（如EMS大廠財務危機），因AR金額大(約100億)，即使1-2%違約率也可能造成1-2億損失，相當於全年營益的5-10%。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>帳齡品質屬業界優等生</strong>：逾期31天以上AR僅佔總額約2%，遠優於業界平均（製造業通常5-10%）。逾180天幾乎為零，顯示收款紀律嚴格。</li><li><strong>營收成長未稀釋AR品質</strong>：2023→2025年營收成長11.2%，AR僅成長15%，DSO從98天微升至101天（+3天），無明顯稀釋效應。這與F01分析的「漲價驅動」效應相符——漲價客戶付款意願通常高於降價衝量客戶。</li><li><strong>現金流量表佐證收款順暢</strong>：F02已確認應收帳款持續回收（2023-2025年應收變動分別為-2.5億、-8.3億、-4.0億，皆為現金流入），與帳齡分析互相印證。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>華新科應收帳款品質在中大型製造業中屬中上水準。DSO 100天偏長為產業結構特徵，但帳齡健康(97%未逾期)、備抵充足(0.78%)、客戶極度分散(無逾10%客戶)是核心品質保證。主要風險在於AR絕對金額大(約100億)，系統性事件可能造成一次性損失。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>計算工具</strong>：財務分析工具.py (receivable_check 2492 2023 2025)</li><li><strong>原始數據</strong>：FinMind TaiwanStockBalanceSheet + TaiwanStockMonthRevenue</li><li><strong>年報補充</strong>：2025年報(第41-42頁帳齡分析、第85頁客戶集中度、第40頁信用政策)</li><li><strong>查詢參數</strong>：stock_id=2492, balance_sheet range=2023-01-01~2026-05-12</li><li><strong>關鍵核對碼</strong>：2025年底AR淨額10,045,684仟元，備抵損失84,085仟元，未逾期佔97%</li><li><strong>數據查詢日期</strong>：2026-05-12</li></ul>',24)])])}const u=t(i,[["render",e]]);export{c as __pageData,u as default};
